  @protected
  void sse_encode_jolt_error(JoltError self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case JoltError_EvalError(message: final message, stack: final stack):
        sse_encode_i_32(0, serializer);
        sse_encode_String(message, serializer);
        sse_encode_opt_String(stack, serializer);
      case JoltError_ConversionError(field0: final field0):
        sse_encode_i_32(1, serializer);
        sse_encode_String(field0, serializer);
      case JoltError_RuntimeError(field0: final field0):
        sse_encode_i_32(2, serializer);
        sse_encode_String(field0, serializer);
      case JoltError_FunctionNotFound(field0: final field0):
        sse_encode_i_32(3, serializer);
        sse_encode_String(field0, serializer);
