  @protected
  void sse_encode_js_entry(JsEntry self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    sse_encode_String(self.key, serializer);
    sse_encode_js_value(self.value, serializer);
